import{_ as a,c as t,o as i,ag as r}from"./chunks/framework.Cycwnjj0.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":null}'),o={name:"guide/index.md"};function n(s,e,l,d,c,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>OxiDex is a modern, high-performance Rust implementation of the industry-standard <a href="https://exiftool.org/" target="_blank" rel="noreferrer">ExifTool</a> metadata management library and command-line application.</p><h2 id="what-is-oxidex" tabindex="-1">What is OxiDex? <a class="header-anchor" href="#what-is-oxidex" aria-label="Permalink to &quot;What is OxiDex?&quot;">​</a></h2><p>OxiDex provides a memory-safe, high-performance alternative to the Perl-based ExifTool while maintaining full compatibility with its extensive metadata tag support. It delivers superior performance through zero-cost abstractions, native cross-compilation capabilities, and seamless integration into modern software ecosystems.</p><h2 id="key-capabilities" tabindex="-1">Key Capabilities <a class="header-anchor" href="#key-capabilities" aria-label="Permalink to &quot;Key Capabilities&quot;">​</a></h2><h3 id="metadata-extraction" tabindex="-1">Metadata Extraction <a class="header-anchor" href="#metadata-extraction" aria-label="Permalink to &quot;Metadata Extraction&quot;">​</a></h3><p>Read metadata from 300+ file formats including images (JPEG, PNG, TIFF, RAW), videos (MP4, MKV, AVI), audio (MP3, FLAC), and documents (PDF).</p><h3 id="metadata-writing" tabindex="-1">Metadata Writing <a class="header-anchor" href="#metadata-writing" aria-label="Permalink to &quot;Metadata Writing&quot;">​</a></h3><p>Modify EXIF, XMP, and IPTC metadata with atomic file operations ensuring data integrity.</p><h3 id="batch-processing" tabindex="-1">Batch Processing <a class="header-anchor" href="#batch-processing" aria-label="Permalink to &quot;Batch Processing&quot;">​</a></h3><p>Process thousands of files in parallel, leveraging all CPU cores for maximum performance.</p><h3 id="format-detection" tabindex="-1">Format Detection <a class="header-anchor" href="#format-detection" aria-label="Permalink to &quot;Format Detection&quot;">​</a></h3><p>Automatically identify file formats using magic byte detection, even when file extensions are incorrect.</p><h2 id="who-should-use-oxidex" tabindex="-1">Who Should Use OxiDex? <a class="header-anchor" href="#who-should-use-oxidex" aria-label="Permalink to &quot;Who Should Use OxiDex?&quot;">​</a></h2><p><strong>Photographers:</strong> Manage metadata in large photo libraries efficiently. Process 1000 RAW files in under 200ms.</p><p><strong>Archivists:</strong> Preserve and extract metadata from diverse file formats with memory-safe operations.</p><p><strong>Developers:</strong> Integrate metadata management into applications via Rust library API or C FFI bindings.</p><p><strong>System Administrators:</strong> Deploy static binaries with no runtime dependencies across multiple platforms.</p><h2 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to &quot;Current Status&quot;">​</a></h2><p><strong>Version:</strong> 1.1.0 (Stable Release)</p><ul><li>✅ 32,677 metadata tags (113% of ExifTool&#39;s 28,853 tags)</li><li>✅ 140+ format families with complete ExifTool parity</li><li>✅ 3.7-9.7x performance improvement</li><li>✅ Full CLI with backward compatibility</li><li>✅ Rust library API and C FFI bindings</li><li>✅ Cross-platform binaries (Linux, macOS, Windows)</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/guide/getting-started">Installation Guide</a> - Install OxiDex via cargo, homebrew, or binaries</li><li><a href="/guide/cli-usage">CLI Usage</a> - Learn command-line interface</li><li><a href="/guide/library-api">Library API</a> - Integrate OxiDex into Rust projects</li><li><a href="/performance/">Performance</a> - View benchmark comparisons</li></ul><h2 id="project-goals" tabindex="-1">Project Goals <a class="header-anchor" href="#project-goals" aria-label="Permalink to &quot;Project Goals&quot;">​</a></h2><ol><li><strong>100% ExifTool Tag Parity:</strong> Support all 32,677+ metadata tags</li><li><strong>High Performance:</strong> 10-100x faster than Perl implementation</li><li><strong>Memory Safety:</strong> Eliminate vulnerabilities through Rust&#39;s ownership system</li><li><strong>Drop-in Replacement:</strong> CLI compatibility for seamless migration</li><li><strong>Developer-Friendly:</strong> Clean API for library and FFI integration</li></ol><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p>OxiDex is released under the GNU General Public License v3.0 (GPL-3.0).</p><h2 id="acknowledgments" tabindex="-1">Acknowledgments <a class="header-anchor" href="#acknowledgments" aria-label="Permalink to &quot;Acknowledgments&quot;">​</a></h2><p>This project is inspired by <a href="https://exiftool.org/" target="_blank" rel="noreferrer">ExifTool</a> by Phil Harvey. OxiDex is an independent reimplementation and is not affiliated with or endorsed by the original ExifTool project.</p>',29)])])}const u=a(o,[["render",n]]);export{p as __pageData,u as default};
